INSERT INTO GACHA_SERIES (
       id
     , title
     , manufacturer
     , price
     , view_count
     , file_id
     , released_at
     , created_at
)
VALUES (
       #{id}
     , #{title}
     , #{manufacturer}
     , #{price}
     , #{viewCount}
     , #{fileId}
     , #{releasedAt}
     , CURRENT_TIMESTAMP
)

INSERT INTO GACHA_ITEM (
       series_id
     , name
     , created_at
)
VALUES (
       #{seriesId}
     , #{name}
     , CURRENT_TIMESTAMP
)
